<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Conway's Game of Life</title>
<style>
  :root {
    --bg: #0f1117;
    --panel: #1a1d27;
    --accent: #6be3ff;
    --accent2: #ff6b9d;
    --grid-line: #262a38;
    --alive: #6be3ff;
    --dead: #171a24;
    --text: #e6e8ef;
  }
  * { box-sizing: border-box; }
  html, body {
    margin: 0;
    height: 100%;
    background: var(--bg);
    color: var(--text);
    font-family: 'Segoe UI', Roboto, system-ui, sans-serif;
    display: flex;
    align-items: center;
    justify-content: center;
  }
  .app {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 16px;
    padding: 24px;
  }
  h1 {
    margin: 0;
    font-size: 1.4rem;
    letter-spacing: 0.05em;
    background: linear-gradient(90deg, var(--accent), var(--accent2));
    -webkit-background-clip: text;
    background-clip: text;
    color: transparent;
  }
  .board-wrap {
    background: var(--panel);
    padding: 12px;
    border-radius: 12px;
    box-shadow: 0 8px 30px rgba(0,0,0,0.5);
  }
  #life {
    display: block;
    background: var(--dead);
    border-radius: 6px;
    cursor: crosshair;
    touch-action: none;
  }
  .controls {
    display: flex;
    gap: 10px;
    flex-wrap: wrap;
    justify-content: center;
  }
  button {
    background: #232733;
    color: var(--text);
    border: 1px solid #333846;
    padding: 10px 18px;
    border-radius: 8px;
    font-size: 0.95rem;
    cursor: pointer;
    transition: transform 0.08s ease, background 0.15s ease, box-shadow 0.15s ease;
  }
  button:hover {
    background: #2b3040;
    box-shadow: 0 0 12px rgba(107, 227, 255, 0.25);
  }
  button:active {
    transform: scale(0.95);
  }
  #play.playing {
    background: var(--accent2);
    color: #1a0a13;
    border-color: var(--accent2);
  }
  .status {
    font-size: 0.85rem;
    color: #8a90a3;
  }
</style>
</head>
<body>
<div class="app">
  <h1>Conway's Game of Life</h1>
  <div class="board-wrap">
    <canvas id="life" width="400" height="400"></canvas>
  </div>
  <div class="controls">
    <button id="step">⏭ Step</button>
    <button id="play">▶ Play</button>
    <button id="random">🎲 Random</button>
    <button id="clear">🗑 Clear</button>
  </div>
  <div class="status" id="status">Generation: 0 &middot; Alive: 0</div>
</div>

<script>
(function () {
  const W = 50, H = 50;
  const canvas = document.getElementById('life');
  const ctx = canvas.getContext('2d');
  const cssSize = 400;
  canvas.style.width = cssSize + 'px';
  canvas.style.height = cssSize + 'px';

  const dpr = window.devicePixelRatio || 1;
  canvas.width = cssSize * dpr;
  canvas.height = cssSize * dpr;
  ctx.scale(dpr, dpr);

  const cellSize = cssSize / W;

  let grid = new Uint8Array(W * H);
  let generation = 0;

  function idx(x, y) { return y * W + x; }

  function get(x, y) {
    if (x < 0 || y < 0 || x >= W || y >= H) return 0;
    return grid[idx(x, y)];
  }

  function set(x, y, v) {
    if (x < 0 || y < 0 || x >= W || y >= H) return;
    grid[idx(x, y)] = v ? 1 : 0;
    draw();
  }

  function clear() {
    grid.fill(0);
    generation = 0;
    draw();
  }

  function countNeighbors(x, y) {
    let n = 0;
    for (let dy = -1; dy <= 1; dy++) {
      for (let dx = -1; dx <= 1; dx++) {
        if (dx === 0 && dy === 0) continue;
        n += get(x + dx, y + dy);
      }
    }
    return n;
  }

  function step() {
    const next = new Uint8Array(W * H);
    for (let y = 0; y < H; y++) {
      for (let x = 0; x < W; x++) {
        const alive = grid[idx(x, y)];
        const n = countNeighbors(x, y);
        if (alive) {
          next[idx(x, y)] = (n === 2 || n === 3) ? 1 : 0;
        } else {
          next[idx(x, y)] = (n === 3) ? 1 : 0;
        }
      }
    }
    grid = next;
    generation++;
    draw();
  }

  function randomize() {
    for (let i = 0; i < grid.length; i++) {
      grid[i] = Math.random() < 0.25 ? 1 : 0;
    }
    generation = 0;
    draw();
  }

  function draw() {
    ctx.fillStyle = getComputedStyle(document.documentElement).getPropertyValue('--dead').trim() || '#171a24';
    ctx.fillRect(0, 0, cssSize, cssSize);

    let aliveCount = 0;
    ctx.fillStyle = getComputedStyle(document.documentElement).getPropertyValue('--alive').trim() || '#6be3ff';
    for (let y = 0; y < H; y++) {
      for (let x = 0; x < W; x++) {
        if (grid[idx(x, y)]) {
          aliveCount++;
          const px = x * cellSize;
          const py = y * cellSize;
          ctx.fillRect(px + 0.5, py + 0.5, cellSize - 1, cellSize - 1);
        }
      }
    }

    ctx.strokeStyle = '#262a38';
    ctx.lineWidth = 0.5;
    ctx.beginPath();
    for (let x = 0; x <= W; x++) {
      ctx.moveTo(x * cellSize, 0);
      ctx.lineTo(x * cellSize, cssSize);
    }
    for (let y = 0; y <= H; y++) {
      ctx.moveTo(0, y * cellSize);
      ctx.lineTo(cssSize, y * cellSize);
    }
    ctx.stroke();

    const status = document.getElementById('status');
    if (status) {
      status.textContent = `Generation: ${generation} · Alive: ${aliveCount}`;
    }
  }

  // ---- Interaction: click/drag to paint ----
  let painting = false;
  let paintValue = 1;

  function cellFromEvent(e) {
    const rect = canvas.getBoundingClientRect();
    const clientX = e.touches ? e.touches[0].clientX : e.clientX;
    const clientY = e.touches ? e.touches[0].clientY : e.clientY;
    const x = Math.floor((clientX - rect.left) / (rect.width / W));
    const y = Math.floor((clientY - rect.top) / (rect.height / H));
    return { x, y };
  }

  function startPaint(e) {
    e.preventDefault();
    const { x, y } = cellFromEvent(e);
    if (x < 0 || y < 0 || x >= W || y >= H) return;
    paintValue = get(x, y) ? 0 : 1;
    painting = true;
    set(x, y, paintValue);
  }

  function movePaint(e) {
    if (!painting) return;
    e.preventDefault();
    const { x, y } = cellFromEvent(e);
    if (x < 0 || y < 0 || x >= W || y >= H) return;
    set(x, y, paintValue);
  }

  function endPaint() {
    painting = false;
  }

  canvas.addEventListener('mousedown', startPaint);
  canvas.addEventListener('mousemove', movePaint);
  window.addEventListener('mouseup', endPaint);
  canvas.addEventListener('touchstart', startPaint, { passive: false });
  canvas.addEventListener('touchmove', movePaint, { passive: false });
  window.addEventListener('touchend', endPaint);

  // ---- Controls ----
  let playing = false;
  let playInterval = null;

  const playBtn = document.getElementById('play');

  function togglePlay() {
    playing = !playing;
    if (playing) {
      playBtn.textContent = '⏸ Pause';
      playBtn.classList.add('playing');
      playInterval = setInterval(step, 150);
    } else {
      playBtn.textContent = '▶ Play';
      playBtn.classList.remove('playing');
      clearInterval(playInterval);
      playInterval = null;
    }
  }

  document.getElementById('step').addEventListener('click', () => {
    if (playing) togglePlay();
    step();
  });
  document.getElementById('play').addEventListener('click', togglePlay);
  document.getElementById('random').addEventListener('click', () => {
    if (playing) togglePlay();
    randomize();
  });
  document.getElementById('clear').addEventListener('click', () => {
    if (playing) togglePlay();
    clear();
  });

  // ---- Public API ----
  window.life = {
    w: W,
    h: H,
    get,
    set,
    step,
    clear,
  };

  draw();
})();
</script>
</body>
</html>
